class Solution {
public:
    int arrayNesting(vector<int>& nums) {
        vector<bool> seen(nums.size());
        int ans = 0;
        for (int i = 0; i < (int)nums.size(); i++) {
            if (seen[i]) continue;
            int cnt = 0, j = i;
            while (!seen[j]) { seen[j]=true; j=nums[j]; cnt++; }
            ans = max(ans, cnt);
        }
        return ans;
    }
};
